import sys

def solve():
    data = sys.stdin.read().split()
    idx = 0
    N = int(data[idx]); idx += 1
    s = [int(x) for x in data[idx:idx+N]]; idx += N
    t = [int(x) for x in data[idx:idx+N]]; idx += N
    MOD = 10**9 + 7

    # items: (size, type) type 0=cow, 1=barn. Sort ascending; ties: cows (0) before barns (1).
    items = []
    for x in s: items.append((x, 0))
    for x in t: items.append((x, 1))
    items.sort(key=lambda x: (x[0], x[1]))

    # dp[c_open][committed], committed in {0,1}
    # Use two arrays
    dpF = [0]*(N+2)  # committed=False
    dpT = [0]*(N+2)  # committed=True
    dpF[0] = 1

    for (val, typ) in items:
        nF = [0]*(N+2)
        nT = [0]*(N+2)
        if typ == 0:
            # cow: (a) reserve c_open++, (b) leave unmatched -> committed=True
            for c in range(N+1):
                if dpF[c]:
                    nF[c+1] = (nF[c+1] + dpF[c]) % MOD  # reserve
                    nT[c] = (nT[c] + dpF[c]) % MOD     # unmatched
                if dpT[c]:
                    nT[c+1] = (nT[c+1] + dpT[c]) % MOD  # reserve
                    nT[c] = (nT[c] + dpT[c]) % MOD     # unmatched (already committed)
        else:
            # barn: (a) match past pending cow (x c_open), (b) leave unmatched (requires committed=False)
            for c in range(N+1):
                if dpF[c]:
                    if c >= 1:
                        nF[c-1] = (nF[c-1] + dpF[c]*c) % MOD
                    nF[c] = (nF[c] + dpF[c]) % MOD  # unmatched (committed=F so OK)
                if dpT[c]:
                    if c >= 1:
                        nT[c-1] = (nT[c-1] + dpT[c]*c) % MOD
                    # cannot leave unmatched when committed=T
        dpF = nF
        dpT = nT

    ans = (dpF[0] + dpT[0]) % MOD
    print(ans)

